#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int t,n,i,j,ans,cnt[10][10];
string s,st;
bool vs[10],vt[10];
vector<int>v;
void dfs(int x,int sc)
{
    if(x==v.size())
    {
        ans=max(ans,sc);
        return;
    }
    int u=v[x];
    FOR(i,0,9)
    {
        if(!vt[i])
        {
            vt[i]=1;
            dfs(x+1,sc+cnt[u][i]);
            vt[i]=0;
        }
    }
}

signed main(void)
{
    t=read();
    wh(t--)
    {
        n=read();
        cin>>s>>st;
        cl(cnt),cl(vs),cl(vt);
        v.clear();
        ans=0;
        FOR(i,0,n-1)
        {
            ++cnt[s[i]-'0'][st[i]-'0'];
            vs[s[i]-'0']=1;
        }
        FOR(i,0,9)
        {
            if(vs[i])
            {
                v.pb(i);
            }
        }
        dfs(0,0);
        writeln(ans);
    }
    return false;
}
